DROP TABLE IF EXISTS [sub_districts];
;
;
CREATE TABLE [sub_districts] (
  SUB_DISTRICT_ID INT NOT NULL IDENTITY(1,1),
  DISTRICT_ID INT DEFAULT NULL,
  CODE NVARCHAR(10) NOT NULL,
  SUB_DISTRICT_CODE NVARCHAR(10) NOT NULL,
  SUB_DISTRICT_THAI NVARCHAR(100) NOT NULL,
  SUB_DISTRICT_ENGLISH NVARCHAR(100) NOT NULL,
  LATITUDE NVARCHAR(50) NOT NULL,
  LONGITUDE NVARCHAR(50) NOT NULL,
  POSTAL_CODE NVARCHAR(10) NOT NULL,
  UPDATED_AT DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(),
  CREATED_AT DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(),
  PRIMARY KEY (SUB_DISTRICT_ID),
  CONSTRAINT UQ_SUB_DISTRICT_CODE UNIQUE (SUB_DISTRICT_CODE),
  CONSTRAINT sub_districts_ibfk_1 FOREIGN KEY (DISTRICT_ID) REFERENCES districts (DISTRICT_ID)
);
;

;

