DROP TABLE IF EXISTS [districts];
;
;
CREATE TABLE [districts] (
  DISTRICT_ID INT NOT NULL IDENTITY(1,1),
  PROVINCE_ID INT DEFAULT NULL,
  CODE NVARCHAR(10) NOT NULL,
  DISTRICT_CODE NVARCHAR(10) NOT NULL,
  DISTRICT_THAI NVARCHAR(100) NOT NULL,
  DISTRICT_ENGLISH NVARCHAR(100) NOT NULL,
  UPDATED_AT DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(),
  CREATED_AT DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(),
  PRIMARY KEY (DISTRICT_ID),
  CONSTRAINT districts_ibfk_1 FOREIGN KEY (PROVINCE_ID) REFERENCES provinces (PROVINCE_ID)
);
;

;

